        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), n1 = 0, n2 = 0, n3 = 0, v = f._language == 'v', g = f.getItem('d66')._controlBehavior;
var l1 = g._getColumnOrder('stt_rec_lx'), l2 = g._getColumnOrder('stt_rec_hd'), l3 = g._getColumnOrder('stt_rec_dh');
var e1 = (v ? 'Mã giao dịch hoặc xử lý không đúng.' : 'Invalid transaction code.');
var e2 = (v ? 'Thông tin mã khách của phiếu xuất phải giống với lệnh xuất kho, đơn hàng hoặc hóa đơn.' : 'Pick List should have same customer information as Issuing Order, Sales Order or Sales Invoice.');
var e3 = (v ? 'Dữ liệu trong chi tiết không được lấy từ nhiều lệnh xuất kho.' : 'Data in grid form should not be extracted from Issuing Orders.');
var e4 = (v ? 'Dữ liệu trong chi tiết chỉ được lấy số liệu từ lệnh xuất kho, đơn hàng hoặc hóa đơn.' : 'Data in grid form must be extracted from Issuing Order, Sales Order or Sales Invoice.');

if($func.trim(f.getItemValue('loai_ct')) == f.getItemValue('status')) {
  $func.hideWait(id);
  $message.show(e1, String.format('$find(\'{0}\').getItem(\'ma_gd\').focus()', id));
  f._checked = false;
}

if (f._checked) {
  var t = f.getItemValue('ma_kh'), c = '', q = ($func.trim(f.getItemValue('loai_ct')) == '1');
  for (var i = 1; i <= g._rowCount; i++) {
    var v1 = (g._getItemValue(i, l1) != ''), v2 = (g._getItemValue(i, l2) != ''), v3 = (g._getItemValue(i, l3) != '');
    if (v1 || v2 || v3) {
      var u = g._getItem(i, 1)._customerIdentity;
      if (!u) u = (f._action == 'Edit') ? f._customerIdentity : t;
      if (t != u) {
        $func.hideWait(id);
        $message.show(e2, String.format('$find(\'{0}\').getItem(\'ma_kh\').focus()', id));
        f._checked = false;
        break;
      }
      if (f._checked) {
        if (v1) {if (n1 == 0) n1 = 1;}
        else {
          if (v2) {if (n2 == 0) n2 = 1;}
          else {
            if (v3) {if (n3 == 0) n3 = 1;}
          }
        }
      }
    }
    if (!c && q && v1) c = g._getItemValue(i, l1);
    if (c && v1) {
      if (c != g._getItemValue(i, l1)) {
        g._errorMultiIssueObject = g._getItem(1, g._getColumnOrder('ma_vt'));
        $func.hideWait(id);
        $message.show(e3, String.format('$find(\'{0}\').focus(\'d66\');$find(\'{1}\')._errorMultiIssueObject.focus()', id, g.get_id()));
        f._checked = false;
        break;
      }
    }
  }
}

if (f._checked) {
  if (n1 + n2 + n3 > 1) {
    f._errorWarningObject = g._getItem(1, g._getColumnOrder('ma_vt'));
    $func.hideWait(id);
    $message.show(e4, String.format('var f = $find(\'{0}\');f.focus(\'d66\');f._errorWarningObject.focus()', id));
    f._checked = false;
  }
}

f.setItemValue('ngay_ct', f.getItemValue('ngay_lct'));
/* </flatten> */
